DLIB_ENABLE_ASSERTS=OFF
DLIB_ENABLE_STACK_TRACE=OFF
DLIB_JPEG_SUPPORT=OFF
DLIB_PNG_SUPPORT=OFF
DLIB_GIF_SUPPORT=OFF
DLIB_LINK_WITH_SQLITE3=OFF

